	addr := os.Getenv("VALKEY_ADDR")
	password := os.Getenv("VALKEY_PASSWORD")
	required := strings.ToLower(os.Getenv("VALKEY_PASSWORD_REQUIRED"))

	if addr == "" {
		return nil, nil
	}
	if password == "" && required != "false" {
		return nil, nil
	}

