		InitAddress: strings.Split(addr, ","),
		Password:    password,
	}

	if strings.ToLower(os.Getenv("VALKEY_DISABLE_CACHE")) == "true" {
		val, _ := strconv.ParseBool(os.Getenv("VALKEY_DISABLE_CACHE"))
