package router

import (
	"net/http"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/api"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

type SessionManager interface {
	GetSandboxBySession(sessionID string) (*store.SandboxInfo, error)
}

type manager struct {
	store            store.Store
	workloadManagerURL string
}

func NewSessionManager(store store.Store, workloadManagerURL string) SessionManager {
	return &manager{
		store:            store,
		workloadManagerURL: workloadManagerURL,
	}
}

func (m *manager) GetSandboxBySession(sessionID string) (*store.SandboxInfo, error) {
	return m.store.GetSandboxBySessionID(sessionID)
}

type Config struct {
	Port                  int
	Debug                 bool
	EnableTLS              bool
	TLSCert               string
	TLSKey                string
	MaxConcurrentRequests int
	WorkloadManagerURL    string
	AgentCubeNamespace    string
}

type Server struct {
	config      *Config
	engine      *gin.Engine
	httpServer  *http.Server
	sessionMgr  SessionManager
	jwtMgr     *JWTManager
	store       store.Store
}

func NewServer(cfg *Config, sessionMgr SessionManager, jwtMgr *JWTManager, store store.Store) *Server {
	if cfg.MaxConcurrentRequests <= 0 {
		cfg.MaxConcurrentRequests = 1000
	}

	gin.SetMode(gin.ReleaseMode)
	engine := gin.New()
	engine.Use(gin.Recovery())
	engine.Use(loggingMiddleware())
	engine.Use(concurrencyLimitMiddleware(cfg.MaxConcurrentRequests))

	engine.GET("/health/live", handleHealthLive)
	engine.GET("/health/ready", handleHealthReady(store))

	engine.POST("/v1/namespaces/:namespace/agent-runtimes/:name/invocations/", m.handleAgentInvoke(sessionMgr, jwtMgr))
	engine.POST("/v1/namespaces/:namespace/code-interpreters/:name/invocations/", m.handleCodeInterpreterInvoke(sessionMgr, jwtMgr))

	server := &Server{
		config:     cfg,
		engine:     engine,
		sessionMgr: sessionMgr,
		jwtMgr:    jwtMgr,
		store:      store,
	}

	server.httpServer = &http.Server{
		Addr:           strings.Join([]string{":", string(rune(cfg.Port))}, ""),
		Handler:        engine,
		ReadTimeout:    30 * time.Second,
		IdleTimeout:    90 * time.Second,
	}

	return server
}

func (s *Server) Start() error {
	if s.config.EnableTLS {
		if s.config.TLSCert == "" || s.config.TLSKey == "" {
			return api.NewValidationError("tls", "both TLS cert and key are required")
		}
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}
	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	return s.httpServer.Shutdown(ctx)
}

func loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		c.Next()
	}
}

func concurrencyLimitMiddleware(maxConcurrent int) gin.HandlerFunc {
	sem := make(chan struct{}, maxConcurrent)
	return func(c *gin.Context) {
		select {
		case sem <- struct{}{}:
			defer func() { <-sem }()
			c.Next()
		default:
			c.JSON(http.StatusTooManyRequests, gin.H{
				"error": "server overloaded, please try again later",
				"code":  "SERVER_OVERLOADED",
			})
			c.Abort()
		}
	}
}

func handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func handleHealthReady(store store.Store) gin.HandlerFunc {
	return func(c *gin.Context) {
		if err := store.Ping(); err != nil {
			c.JSON(http.StatusServiceUnavailable, gin.H{"status": "not ready", "error": err.Error()})
			return
		}
		c.JSON(http.StatusOK, gin.H{"status": "ready"})
	}
}

func (s *Server) handleAgentInvoke(sessionMgr SessionManager, jwtMgr *JWTManager) gin.HandlerFunc {
	return func(c *gin.Context) {
		sessionID := c.GetHeader("x-agentcube-session-id")
		namespace := c.Param("namespace")
		name := c.Param("name")

		var sandboxInfo *store.SandboxInfo
		var err error

		if sessionID == "" {
			req := &types.CreateSandboxRequest{
				Kind:      types.AgentRuntimeKind,
				Name:      name,
				Namespace: namespace,
			}
			if err := req.Validate(); err != nil {
				c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
				return
			}
			sandboxInfo, err = s.createSandbox(req)
			if err != nil {
				handleGetSandboxError(c, err)
				return
			}
			sessionID = sandboxInfo.ID
		} else {
			sandboxInfo, err = sessionMgr.GetSandboxBySession(sessionID)
			if err != nil {
				handleGetSandboxError(c, err)
				return
			}
		}

		s.forwardToSandbox(c, sandboxInfo, jwtMgr, sessionID)
	}
}

func (s *Server) handleCodeInterpreterInvoke(sessionMgr SessionManager, jwtMgr *JWTManager) gin.HandlerFunc {
	return func(c *gin.Context) {
		sessionID := c.GetHeader("x-agentcube-session-id")
		namespace := c.Param("namespace")
		name := c.Param("name")

		var sandboxInfo *store.SandboxInfo
		var err error

		if sessionID == "" {
			req := &types.CreateSandboxRequest{
				Kind:      types.CodeInterpreterKind,
				Name:      name,
				Namespace: namespace,
			}
			if err := req.Validate(); err != nil {
				c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
				return
			}
			sandboxInfo, err = s.createSandbox(req)
			if err != nil {
				handleGetSandboxError(c, err)
				return
			}
			sessionID = sandboxInfo.ID
		} else {
			sandboxInfo, err = sessionMgr.GetSandboxBySession(sessionID)
			if err != nil {
				handleGetSandboxError(c, err)
				return
			}
		}

		s.forwardToSandbox(c, sandboxInfo, jwtMgr, sessionID)
	}
}

func (s *Server) createSandbox(req *types.CreateSandboxRequest) (*store.SandboxInfo, error) {
	client := &http.Client{
		Transport: &http.Transport{
			IdleConnTimeout: 0,
		},
	}

	tokenData, _ := readServiceAccountToken()
	var body []byte
	if tokenData != "" {
		reqBody, _ := json.Marshal(req)
		body = reqBody
	}

	httpReq, _ := http.NewRequest("POST", s.config.WorkloadManagerURL+"/v1/code-interpreter", bytes.NewReader(body))
	if tokenData != "" {
		httpReq.Header.Set("Authorization", "Bearer "+tokenData)
	}
	httpReq.Header.Set("Content-Type", "application/json")

	resp, err := client.Do(httpReq)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK && resp.StatusCode != http.StatusCreated {
		return nil, api.NewUpstreamUnavailableError("failed to create sandbox")
	}

	var result struct {
		SessionID   string              `json:"sessionId"`
		Namespace   string              `json:"namespace"`
		EntryPoints []store.EntryPoint  `json:"entryPoints"`
		ExpiresAt   int64               `json:"expiresAt,omitempty"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
		return nil, err
	}

	return &store.SandboxInfo{
		ID:          result.SessionID,
		Kind:        req.Kind,
		Namespace:   result.Namespace,
		Name:        req.Name,
		EntryPoints: result.EntryPoints,
		ExpiresAt:   result.ExpiresAt,
	}, nil
}

func (s *Server) forwardToSandbox(c *gin.Context, sandboxInfo *store.SandboxInfo, jwtMgr *JWTManager, sessionID string) {
	var upstreamURL string

	if len(sandboxInfo.EntryPoints) > 0 {
		entryPoint := sandboxInfo.EntryPoints[0]
		upstreamURL = "http://" + sandboxInfo.PodIP + ":" + string(rune(entryPoint.TargetPort)) + entryPoint.Path
	} else {
		c.JSON(http.StatusNotFound, gin.H{"error": "no entry point found for sandbox"})
		return
	}

	proxy := httputil.NewSingleHostReverseProxy(upstreamURL)
	originalDirector := proxy.Director
	proxy.Director = func(req *http.Request) {
		originalDirector(req)
		req.URL.Scheme = "http"
		req.URL.Host = req.Host
		req.Header.Set("X-Forwarded-Host", req.Host)
		req.Header.Set("X-Forwarded-Proto", "http")
		req.Header.Set("X-Forwarded-For", c.ClientIP())

		if sandboxInfo.Kind == types.SandboxKind || sandboxInfo.Kind == types.SandboxClaimsKind {
			token, err := jwtMgr.GenerateToken(jwtClaims{
				SessionID: sessionID,
				Namespace: sandboxInfo.Namespace,
				PodName:  sandboxInfo.PodName,
			})
			if err != nil {
				c.JSON(http.StatusInternalServerError, gin.H{
					"code":  "JWT_SIGNING_FAILED",
					"error": "failed to sign request",
				})
				return
			}
			req.Header.Set("Authorization", "Bearer "+token)
		}
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set("x-agentcube-session-id", sessionID)
		return nil
	}

	proxy.ServeHTTP(c.Writer, c.Request)

	s.updateLastActivity(sessionID)
}

func (s *Server) updateLastActivity(sessionID string) {
	now := time.Now().Unix()
	if err := s.store.UpdateSessionLastActivity(sessionID, now); err != nil {
		// log warning only
	}
}

func handleGetSandboxError(c *gin.Context, err error) {
	if err == store.ErrNotFound {
		c.JSON(http.StatusNotFound, gin.H{
			"error": "session not found",
			"code":  "SESSION_NOT_FOUND",
		})
		return
	}
	if strings.Contains(err.Error(), "connection refused") {
		c.JSON(http.StatusBadGateway, gin.H{"error": "sandbox unreachable"})
		return
	}
	if strings.Contains(err.Error(), "timeout") {
		c.JSON(http.StatusGatewayTimeout, gin.H{"error": "sandbox timeout"})
		return
	}
	c.JSON(http.StatusBadGateway, gin.H{"error": err.Error()})
}

func readServiceAccountToken() (string, error) {
	data, err := os.ReadFile("/var/run/secrets/kubernetes.io/serviceaccount/token")
	if err != nil {
		if os.IsNotExist(err) {
			return "", nil
		}
		return "", err
	}
	return strings.TrimSpace(string(data)), nil
}

import (
	"bytes"
	"encoding/json"
	"github.com/golang-jwt/jwt/v5"
	httputil "net/http/httputil"
	"os"
)

type jwtClaims struct {
	jwt.RegisteredClaims
	SessionID  string `json:"session_id"`
	Namespace  string `json:"namespace"`
	PodName    string `json:"pod_name"`
}

type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
	namespace  string
	mu         sync.RWMutex
}

func NewJWTManager(namespace string) *JWTManager {
	return &JWTManager{
		namespace: namespace,
	}
}

func (j *JWTManager) GenerateToken(claims jwtClaims) (string, error) {
	j.mu.RLock()
	defer j.mu.RUnlock()

	if j.privateKey == nil {
		return "", errors.New("private key not initialized")
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	token.Claims.Issuer = "agentcube-router"
	token.Claims.ExpiresAt = jwt.NewNumericDate(time.Now().Add(5 * time.Minute))

	return token.SignedString(j.privateKey)
}

func (j *JWTManager) SetKeys(privateKey *rsa.PrivateKey, publicKey *rsa.PublicKey) {
	j.mu.Lock()
	defer j.mu.Unlock()
	j.privateKey = privateKey
	j.publicKey = publicKey
}

func (j *JWTManager) PublicKey() *rsa.PublicKey {
	j.mu.RLock()
	defer j.mu.RUnlock()
	return j.publicKey
}

