	PrivateKeyDataKey      = "private.pem"
	IdentityNamespaceEnv   = "AGENTCUBE_NAMESPACE"
	DefaultIdentityNamespace = "default"
)

func (j *JWTManager) TryStoreOrLoadJWTKeySecret(clientset *kubernetes.Clientset, namespace string) error {
	if namespace == "" {
		namespace = os.Getenv(IdentityNamespaceEnv)
		if namespace == "" {
			namespace = DefaultIdentityNamespace
		}
	}

	secret, err := clientset.CoreV1().Secrets(namespace).Get(context.Background(), IdentitySecretName, metav1.GetOptions{})
	if err != nil {
		if os.IsNotExist(err) {
			return j.createAndStoreJWTKeySecret(clientset, namespace)
		}
		return fmt.Errorf("failed to get secret: %w", err)
	}

	privateKeyPEM, ok := secret.Data[PrivateKeyDataKey]
	if !ok {
		return fmt.Errorf("private key not found in secret")
	}
	publicKeyPEM, ok := secret.Data[PublicKeyDataKey]
	if !ok {
		return fmt.Errorf("public key not found in secret")
	}

	privateKey, err := parsePrivateKey(privateKeyPEM)
	if err != nil {
		return fmt.Errorf("failed to parse private key: %w", err)
	}
	publicKey, err := parsePublicKey(publicKeyPEM)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %w", err)
	}

	j.SetKeys(privateKey, publicKey)
	return nil
}

func (j *JWTManager) createAndStoreJWTKeySecret(clientset *kubernetes.Clientset, namespace string) error {
	privateKey, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		return fmt.Errorf("failed to generate RSA key: %w", err)
	}

	privateKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: x509.MarshalPKCS1PrivateKey(privateKey),
	})

	publicKeyBytes, err := x509.MarshalPKIXPublicKey(&privateKey.PublicKey)
	if err != nil {
		return fmt.Errorf("failed to marshal public key: %w", err)
	}
	publicKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: publicKeyBytes,
	})

	secret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      IdentitySecretName,
			Namespace: namespace,
		},
		Type: corev1.SecretTypeOpaque,
		Data: map[string][]byte{
			PrivateKeyDataKey: privateKeyPEM,
			PublicKeyDataKey:  publicKeyPEM,
		},
	}

	_, err = clientset.CoreV1().Secrets(namespace).Create(context.Background(), secret, metav1.CreateOptions{})
	if err != nil {
		return fmt.Errorf("failed to create secret: %w", err)
	}

	j.SetKeys(privateKey, &privateKey.PublicKey)
	return nil
}

func parsePrivateKey(data []byte) (*rsa.PrivateKey, error) {
	block, _ := pem.Decode(data)
	if block == nil {
		return nil, fmt.Errorf("failed to decode PEM block")
	}
	return x509.ParsePKCS1PrivateKey(block.Bytes)
}

func parsePublicKey(data []byte) (*rsa.PublicKey, error) {
	block, _ := pem.Decode(data)
	if block == nil {
		return nil, fmt.Errorf("failed to decode PEM block")
	}
	pub, err := x509.ParsePKIXPublicKey(block.Bytes)
	if err != nil {
		return nil, err
	}
	rsaPub, ok := pub.(*rsa.PublicKey)
	if !ok {
		return nil, fmt.Errorf("not an RSA public key")
	}
	return rsaPub, nil
}

