func NewSingleHostReverseProxy(target *url.URL) *httputil.ReverseProxy {
	targetQuery := target.RawQuery
	director := func(req *http.Request) {
		req.URL.Scheme = target.Scheme
		req.URL.Host = target.Host
		req.URL.Path, req.URL.RawPath = joinURLPath(target, req.URL)
		if targetQuery == "" || req.URL.RawQuery == "" {
			req.URL.RawQuery = targetQuery + req.URL.RawQuery
		} else {
			req.URL.RawQuery = targetQuery + "&" + req.URL.RawQuery
		}
		if _, ok := req.Header["User-Agent"]; !ok {
			req.Header.Set("User-Agent", "")
		}
	}
	return &httputil.ReverseProxy{Director: director}
}

func joinURLPath(a, b *url.URL) (path, rawpath string) {
	if a.RawPath == "" || b.RawPath == "" {
		return joinURLPathGeneric(a, b)
	}
	aPath := a.EscapedPath()
	bPath := b.EscapedPath()
	result := aPath[:len(aPath)-len(a.EscapedPath())] + bPath
	return result, result
}

func joinURLPathGeneric(a, b *url.URL) (path, rawpath string) {
	aPath := a.Path
	bPath := b.Path
	if bPath == "" {
		return aPath, a.RawPath
	}
	if aPath[len(aPath)-1] == '/' || bPath[0] == '/' {
		return aPath + bPath, ""
	}
	return aPath + "/" + bPath, ""
}

import "net/url"

package router

import (
	"context"
	"flag"
	"fmt"
	"net/http"
	"os"
	"os/signal"
	"strconv"
	"strings"
	"syscall"
	"time"

	"k8s.io/klog/v2"
)

var (
	port                   = flag.Int("port", 8080, "Port to listen on")
	enableTLS              = flag.Bool("enable-tls", false, "Enable TLS")
	tlsCert                = flag.String("tls-cert", "", "TLS certificate file path")
	tlsKey                 = flag.String("tls-key", "", "TLS key file path")
	debug                  = flag.Bool("debug", false, "Enable debug mode")
	maxConcurrentRequests  = flag.Int("max-concurrent-requests", 1000, "Maximum concurrent requests")
	workloadManagerURL     = os.Getenv("WORKLOAD_MANAGER_URL")
	agentCubeNamespace     = os.Getenv("AGENTCUBE_NAMESPACE")
)

func Run() error {
	klog.InitFlags(nil)
	flag.Parse()

	cfg := &Config{
		Port:                   *port,
		EnableTLS:              *enableTLS,
		TLSCert:                *tlsCert,
		TLSKey:                 *tlsKey,
		Debug:                  *debug,
		MaxConcurrentRequests:  *maxConcurrentRequests,
		WorkloadManagerURL:     workloadManagerURL,
		AgentCubeNamespace:     agentCubeNamespace,
	}

	if cfg.WorkloadManagerURL == "" {
		return fmt.Errorf("WORKLOAD_MANAGER_URL environment variable is required")
	}

	storeInstance := Storage()
	defer storeInstance.Close()

	sessionMgr := NewSessionManager(storeInstance, cfg.WorkloadManagerURL)

	namespace := cfg.AgentCubeNamespace
	if namespace == "" {
		namespace = "default"
	}
	jwtMgr := NewJWTManager(namespace)

	config, err := GetConfig()
	if err == nil {
		clientset, err := GetClientset(config)
		if err == nil {
			if err := jwtMgr.TryStoreOrLoadJWTKeySecret(clientset, namespace); err != nil {
				klog.Warningf("Failed to setup JWT key secret: %v", err)
			}
		}
	}

	server := NewServer(cfg, sessionMgr, jwtMgr, storeInstance)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	go func() {
		sigCh := make(chan os.Signal, 1)
		signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
		<-sigCh
		klog.Info("Shutting down server...")
		cancel()
		shutdownCtx, shutdownCancel := context.WithTimeout(context.Background(), 10*time.Second)
		defer shutdownCancel()
		server.Shutdown(shutdownCtx)
	}()

	klog.Infof("Starting router server on port %d", cfg.Port)
	return server.Start()
}

func GetConfig() (*rest.Config, error) {
	config, err := rest.InClusterConfig()
	if err != nil {
		return nil, err
	}
	config.QPS = 50
	config.Burst = 100
	return config, nil
}

func GetClientset(config *rest.Config) (*kubernetes.Clientset, error) {
	return kubernetes.NewForConfig(config)
}

func GetEnvInt(key string, defaultVal int) int {
	if val := os.Getenv(key); val != "" {
		if intVal, err := strconv.Atoi(val); err == nil {
			return intVal
		}
	}
	return defaultVal
}

func GetEnvString(key string, defaultVal string) string {
	if val := os.Getenv(key); val != "" {
		return val
	}
	return defaultVal
}

func GetEnvBool(key string, defaultVal bool) bool {
	if val := os.Getenv(key); val != "" {
		if boolVal, err := strconv.ParseBool(val); err == nil {
			return boolVal
		}
	}
	return defaultVal
}

func init() {
	workloadManagerURL = GetEnvString("WORKLOAD_MANAGER_URL", "http://localhost:8080")
	agentCubeNamespace = GetEnvString("AGENTCUBE_NAMESPACE", "default")
}

